What does this component display when the user is logged in as Alice?

```jsx
function ProfileBadge() {
  const { user } = useContext(AuthContext);

  if (!user) return null;

  return (
    <div className="badge">
      <img src={user.avatar} alt={user.name} />
      <span>{user.name}</span>
    </div>
  );
}
```

A junior developer asks: "Why is the button always light-colored even though I turned on dark mode?" What is the problem?

```jsx
function App() {
  const [theme, setTheme] = useState('light');
  return (
    <ThemeContext.Provider value={theme}>
      <Settings onThemeChange={setTheme} />
      <MainContent />
    </ThemeContext.Provider>
  );
}

function ActionButton({ label, onClick }) {
  return (
    <button className="btn-light" onClick={onClick}>
      {label}
    </button>
  );
}
```

You are reviewing AI-generated code. The client says "the shopping cart count in the header does not update when I add items from the product page." Both components use CartContext. What would you tell the AI?

```jsx
function CartProvider({ children }) {
  const [items, setItems] = useState([]);
  return (
    <CartContext.Provider value={{ items }}>
      {children}
    </CartContext.Provider>
  );
}

function Header() {
  const { items } = useContext(CartContext);
  return <span>Cart ({items.length})</span>;
}

function ProductPage({ product }) {
  const { items } = useContext(CartContext);

  function addToCart() {
    items.push(product);
  }

  return (
    <button onClick={addToCart}>Add to Cart</button>
  );
}
```
